public enum ConnectionStatus {
    
    case disconnected
    case connectingDirect
    case connectingFragmented
    case connectingReality
    case connected
    case disconnecting
    case error
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeConnectionStatus: FfiConverterRustBuffer {
    typealias SwiftType = ConnectionStatus

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> ConnectionStatus {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .disconnected
        
        case 2: return .connectingDirect
        
        case 3: return .connectingFragmented
        
        case 4: return .connectingReality
        
        case 5: return .connected
        
        case 6: return .disconnecting
        
        case 7: return .error
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: ConnectionStatus, into buf: inout [UInt8]) {
        switch value {
        
        
        case .disconnected:
            writeInt(&buf, Int32(1))
        
        
        case .connectingDirect:
            writeInt(&buf, Int32(2))
        
        
        case .connectingFragmented:
            writeInt(&buf, Int32(3))
        
        
        case .connectingReality:
            writeInt(&buf, Int32(4))
        
        
        case .connected:
            writeInt(&buf, Int32(5))
        
        
        case .disconnecting:
            writeInt(&buf, Int32(6))
        
        
        case .error:
            writeInt(&buf, Int32(7))
        
        }
    }
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public func FfiConverterTypeConnectionStatus_lift(_ buf: RustBuffer) throws -> ConnectionStatus {
    return try FfiConverterTypeConnectionStatus.lift(buf)
